const s="q-basico",n="basico",i="Quiz Básico — No restaurante",r="Escute a conversa e responda em espanhol",t="qb-intro",u="Hora do quiz! Escute a conversa inteira em espanhol — um casal chegando num restaurante. Pode ouvir quantas vezes quiser. Depois, responda às perguntas. Não precisa entender cada palavra: pegue o sentido geral.",d="Um cliente chega num restaurante e fala com a garçonete (la moza).",c=[{audioKey:"qb-d1",voz:"Ana",es:"¡Hola! Buenas tardes, ¿mesa para dos?",pt:"Olá! Boa tarde, mesa para dois?"},{audioKey:"qb-d2",voz:"Diego",es:"Hola, sí, para dos, por favor.",pt:"Olá, sim, para dois, por favor."},{audioKey:"qb-d3",voz:"Ana",es:"Perfecto. ¿Qué van a tomar?",pt:"Perfeito. O que vão querer?"},{audioKey:"qb-d4",voz:"Diego",es:"Yo quiero una milanesa con papas fritas. ¿Cuánto sale?",pt:"Eu quero uma milanesa com batatas fritas. Quanto custa?"},{audioKey:"qb-d5",voz:"Ana",es:"Sale trescientos pesos. ¿Y para tomar?",pt:"Custa trezentos pesos. E para beber?"},{audioKey:"qb-d6",voz:"Diego",es:"Una botella de agua, por favor. ¿Aceptan tarjeta?",pt:"Uma garrafa de água, por favor. Aceitam cartão?"},{audioKey:"qb-d7",voz:"Ana",es:"Sí, aceptamos tarjeta. ¿Algo más?",pt:"Sim, aceitamos cartão. Mais alguma coisa?"},{audioKey:"qb-d8",voz:"Diego",es:"No, gracias. ¿Dónde está el baño?",pt:"Não, obrigado. Onde fica o banheiro?"},{audioKey:"qb-d9",voz:"Ana",es:"Al fondo a la derecha.",pt:"No fundo à direita."},{audioKey:"qb-d10",voz:"Diego",es:"Muchas gracias.",pt:"Muito obrigado."}],l=[{es:"¿Para cuántas personas es la mesa?",opcoes:["Para dos","Para una","Para tres","Para cuatro"],correta:0,pt:"Para quantas pessoas é a mesa?"},{es:"¿Qué pidió de comer el cliente?",opcoes:["Una milanesa con papas fritas","Un asado","Una pizza","Una ensalada"],correta:0,pt:"O que o cliente pediu para comer?"},{es:"¿Cuánto sale la comida?",opcoes:["Trescientos pesos","Trece pesos","Cien pesos","Mil pesos"],correta:0,pt:"Quanto custa a comida?"},{es:"¿Qué pidió para tomar?",opcoes:["Una botella de agua","Un vino","Una cerveza","Un café"],correta:0,pt:"O que pediu para beber?"},{es:"¿Cómo va a pagar?",opcoes:["Con tarjeta","En efectivo","Con cheque","No paga"],correta:0,pt:"Como vai pagar?"},{es:"¿Dónde está el baño?",opcoes:["Al fondo a la derecha","A la izquierda","Arriba","Afuera"],correta:0,pt:"Onde fica o banheiro?"}],p={id:s,nivel:n,titulo:i,subtitulo:r,introAudioKey:t,introPt:u,cenario:d,dialogo:c,perguntas:l},m="q-intermediario",v="intermediario",q="Quiz Intermediário — O fim de semana",g="Escute a conversa e responda em espanhol",b="qi-intro",A="Quiz do Intermediário! Dois amigos conversam sobre o fim de semana e combinam um encontro. Escute a conversa toda — quantas vezes precisar — e depois responda. Foque no sentido geral: o que cada um fez e o que vão fazer.",h="Dois amigos se encontram e conversam sobre o fim de semana.",z=[{audioKey:"qi-d1",voz:"Ana",es:"¡Hola! ¿Cómo andás? ¿Qué hiciste el finde?",pt:"Oi! Como vai? O que você fez no fim de semana?"},{audioKey:"qi-d2",voz:"Diego",es:"¡Bárbaro! Fui a Colonia con unos amigos. La pasamos muy bien.",pt:"Ótimo! Fui a Colonia com uns amigos. A gente se divertiu muito."},{audioKey:"qi-d3",voz:"Ana",es:"¡Qué lindo! ¿Y qué hicieron allá?",pt:"Que legal! E o que fizeram lá?"},{audioKey:"qi-d4",voz:"Diego",es:"Caminamos por el centro, sacamos muchas fotos y comimos un asado increíble.",pt:"Caminhamos pelo centro, tiramos muitas fotos e comemos um churrasco incrível."},{audioKey:"qi-d5",voz:"Ana",es:"¡Me encanta Colonia! ¿Cuándo volviste?",pt:"Adoro Colonia! Quando você voltou?"},{audioKey:"qi-d6",voz:"Diego",es:"El domingo a la noche. Estaba cansadísimo. ¿Y vos, qué vas a hacer este finde?",pt:"Domingo à noite. Estava cansadíssimo. E você, o que vai fazer neste fim de semana?"},{audioKey:"qi-d7",voz:"Ana",es:"Voy a quedarme en casa. La semana que viene tengo mucho trabajo.",pt:"Vou ficar em casa. Na semana que vem tenho muito trabalho."},{audioKey:"qi-d8",voz:"Diego",es:"Dale. Si querés, el sábado tomamos un café.",pt:"Beleza. Se quiser, sábado tomamos um café."},{audioKey:"qi-d9",voz:"Ana",es:"¡Buenísimo! ¿Quedamos a las cuatro?",pt:"Ótimo! Combinamos às quatro?"},{audioKey:"qi-d10",voz:"Diego",es:"Perfecto, nos vemos el sábado.",pt:"Perfeito, a gente se vê no sábado."}],y=[{es:"¿Adónde fue Diego el fin de semana?",opcoes:["A Colonia","A Montevideo","A Buenos Aires","A la playa"],correta:0,pt:"Aonde Diego foi no fim de semana?"},{es:"¿Con quién fue?",opcoes:["Con unos amigos","Solo","Con la familia","Con Ana"],correta:0,pt:"Com quem ele foi?"},{es:"¿Qué comieron allá?",opcoes:["Un asado","Una milanesa","Una pizza","Pescado"],correta:0,pt:"O que comeram lá?"},{es:"¿Cuándo volvió Diego?",opcoes:["El domingo a la noche","El sábado","El lunes","El viernes"],correta:0,pt:"Quando Diego voltou?"},{es:"¿Qué va a hacer Ana este fin de semana?",opcoes:["Quedarse en casa","Viajar","Ir a Colonia","Trabajar el sábado"],correta:0,pt:"O que Ana vai fazer neste fim de semana?"},{es:"¿A qué hora quedaron el sábado?",opcoes:["A las cuatro","A las dos","A las cinco","A las ocho"],correta:0,pt:"A que horas combinaram no sábado?"}],f={id:m,nivel:v,titulo:q,subtitulo:g,introAudioKey:b,introPt:A,cenario:h,dialogo:z,perguntas:y},D="q-avancado",K="avancado",E="Quiz Avançado — No balcão de atendimento",P="Escute a conversa e responda em espanhol",Q="qa-intro",$="Quiz do Avançado! Uma conversa formal num atendimento — registro 'usted', com trâmites e condicional. Escute toda a conversa, quantas vezes precisar, e responda. Preste atenção no que ela precisa, quando fica marcado e como eles se tratam.",C="Uma cliente vai a um balcão de atendimento resolver um trâmite. Tratamento formal (usted).",j=[{audioKey:"qa-d1",voz:"Ana",es:"Buenos días. Vengo a hacer un trámite, necesito sacar un turno.",pt:"Bom dia. Venho fazer um trâmite, preciso marcar um horário."},{audioKey:"qa-d2",voz:"Diego",es:"Buenos días. ¿Para qué fecha le gustaría?",pt:"Bom dia. Para que data a senhora gostaria?"},{audioKey:"qa-d3",voz:"Ana",es:"Si fuera posible, esta semana. ¿Sería mucho pedir?",pt:"Se fosse possível, esta semana. Seria pedir demais?"},{audioKey:"qa-d4",voz:"Diego",es:"Déjeme ver... Podría ser el jueves a las diez. ¿Le parece bien?",pt:"Deixe-me ver... Poderia ser na quinta às dez. A senhora concorda?"},{audioKey:"qa-d5",voz:"Ana",es:"Perfecto. ¿Qué documentación tengo que traer?",pt:"Perfeito. Que documentação tenho que trazer?"},{audioKey:"qa-d6",voz:"Diego",es:"Traiga el documento y un comprobante de domicilio.",pt:"Traga o documento e um comprovante de endereço."},{audioKey:"qa-d7",voz:"Ana",es:"Muchas gracias. ¿Me puede mandar un recordatorio por correo?",pt:"Muito obrigada. O senhor pode me mandar um lembrete por e-mail?"},{audioKey:"qa-d8",voz:"Diego",es:"Claro, no hay problema. Que tenga un buen día.",pt:"Claro, sem problema. Tenha um bom dia."},{audioKey:"qa-d9",voz:"Ana",es:"Igualmente, muchas gracias.",pt:"Igualmente, muito obrigada."}],S=[{es:"¿A qué fue la clienta?",opcoes:["A hacer un trámite","A comprar ropa","A comer","A pagar una multa"],correta:0,pt:"A que a cliente foi?"},{es:"¿Qué necesita exactamente?",opcoes:["Sacar un turno","Un presupuesto","Hacer un reclamo","Cambiar plata"],correta:0,pt:"O que ela precisa exatamente?"},{es:"¿Para qué día quedó el turno?",opcoes:["El jueves a las diez","El martes a las nueve","El viernes a las diez","El lunes a las ocho"],correta:0,pt:"Para que dia ficou marcado?"},{es:"¿Qué documentación tiene que traer?",opcoes:["El documento y un comprobante de domicilio","Solo el documento","Una foto","Nada"],correta:0,pt:"Que documentação tem que trazer?"},{es:"¿Qué registro usan los dos?",opcoes:["Formal (usted)","Informal (vos)","Mezclan los dos","Hablan en inglés"],correta:0,pt:"Que registro os dois usam?"},{es:"¿Cómo se despiden?",opcoes:["Que tenga un buen día","Chau, nos vemos","Hasta mañana","Dale, listo"],correta:0,pt:"Como eles se despedem?"}],O={id:D,nivel:K,titulo:E,subtitulo:P,introAudioKey:Q,introPt:$,cenario:C,dialogo:j,perguntas:S},U="q-b01",N="basico",M="Quiz — Saudações",B="Escute a conversa e responda em espanhol",T="q-b01-i",V="Hora do quiz! Escute esta conversa entre duas pessoas que se conhecem agora. Pode ouvir quantas vezes quiser e depois responda às perguntas em espanhol.",L="Dois turistas se cruzam num café de manhã e se apresentam.",H=[{audioKey:"q-b01-d1",voz:"Ana",es:"¡Hola! Buenos días. ¿Cómo andás?",pt:"Oi! Bom dia. Como vai?"},{audioKey:"q-b01-d2",voz:"Diego",es:"Buenos días. Todo bien, ¿y vos?",pt:"Bom dia. Tudo bem, e você?"},{audioKey:"q-b01-d3",voz:"Ana",es:"Más o menos, un poco cansada. ¿Cómo te llamás?",pt:"Mais ou menos, um pouco cansada. Como você se chama?"},{audioKey:"q-b01-d4",voz:"Diego",es:"Me llamo Diego. ¿Y vos?",pt:"Eu me chamo Diego. E você?"},{audioKey:"q-b01-d5",voz:"Ana",es:"Soy Ana. ¡Mucho gusto, Diego!",pt:"Sou a Ana. Muito prazer, Diego!"},{audioKey:"q-b01-d6",voz:"Diego",es:"Encantado. ¿De dónde sos, Ana?",pt:"Encantado. De onde você é, Ana?"},{audioKey:"q-b01-d7",voz:"Ana",es:"Soy de Brasil, soy brasileña. ¿Y vos?",pt:"Sou do Brasil, sou brasileira. E você?"},{audioKey:"q-b01-d8",voz:"Diego",es:"Yo soy de Uruguay. Perdón, ¿hablás portugués?",pt:"Eu sou do Uruguai. Desculpa, você fala português?"},{audioKey:"q-b01-d9",voz:"Ana",es:"Un poco. No hablo bien español todavía.",pt:"Um pouco. Ainda não falo bem espanhol."},{audioKey:"q-b01-d10",voz:"Diego",es:"¡Tranquila! Hablás muy bien. Bueno, nos vemos. ¡Chau!",pt:"Fica tranquila! Você fala muito bem. Bom, a gente se vê. Tchau!"}],Y=[{es:"¿En qué momento del día se saludan?",opcoes:["A la noche","A la mañana","A la tarde","A la madrugada"],correta:1,pt:"Em que momento do dia eles se cumprimentam?"},{es:"¿Cómo se siente Ana al principio?",opcoes:["Muy bien","Enojada","Más o menos, un poco cansada","Enferma"],correta:2,pt:"Como a Ana se sente no começo?"},{es:"¿Cómo se llama el hombre?",opcoes:["Diego","Pedro","Andrés","Mateo"],correta:0,pt:"Como se chama o homem?"},{es:"¿De dónde es Ana?",opcoes:["De Uruguay","De Argentina","De Chile","De Brasil"],correta:3,pt:"De onde a Ana é?"},{es:"¿De dónde es Diego?",opcoes:["De Brasil","De Uruguay","De España","De México"],correta:1,pt:"De onde o Diego é?"},{es:"¿Qué dice Ana sobre su español?",opcoes:["Que lo habla perfecto","Que no lo entiende nada","Que todavía no lo habla bien","Que no quiere aprender"],correta:2,pt:"O que a Ana diz sobre o espanhol dela?"}],k={id:U,nivel:N,titulo:M,subtitulo:B,introAudioKey:T,introPt:V,cenario:L,dialogo:H,perguntas:Y},x="q-b02",I="basico",F="Quiz — Números, preços e horas",R="Escute a conversa e responda em espanhol",G="q-b02-i",J="Hora do quiz! Escute esta conversa numa feira, com números, preços e horários. Pode ouvir quantas vezes quiser e depois responda às perguntas em espanhol.",w="Uma cliente compra numa banca e combina o horário de voltar.",W=[{audioKey:"q-b02-d1",voz:"Ana",es:"Buenas tardes. ¿Cuánto sale el kilo de manzanas?",pt:"Boa tarde. Quanto custa o quilo de maçãs?"},{audioKey:"q-b02-d2",voz:"Diego",es:"Sale cuarenta pesos el kilo.",pt:"Custa quarenta pesos o quilo."},{audioKey:"q-b02-d3",voz:"Ana",es:"Dame dos kilos, por favor. ¿Cuánto es en total?",pt:"Me dá dois quilos, por favor. Quanto é no total?"},{audioKey:"q-b02-d4",voz:"Diego",es:"Son ochenta pesos.",pt:"São oitenta pesos."},{audioKey:"q-b02-d5",voz:"Ana",es:"Te pago con cien. ¿Me das el vuelto?",pt:"Pago com cem. Pode me dar o troco?"},{audioKey:"q-b02-d6",voz:"Diego",es:"Sí, claro. Acá van veinte pesos de vuelto.",pt:"Sim, claro. Aqui vão vinte pesos de troco."},{audioKey:"q-b02-d7",voz:"Ana",es:"Gracias. ¿A qué hora cierra la feria?",pt:"Obrigada. A que horas a feira fecha?"},{audioKey:"q-b02-d8",voz:"Diego",es:"Cierra a las ocho de la noche.",pt:"Fecha às oito da noite."},{audioKey:"q-b02-d9",voz:"Ana",es:"¿Y abren mañana? Mañana es sábado, ¿no?",pt:"E abrem amanhã? Amanhã é sábado, não é?"},{audioKey:"q-b02-d10",voz:"Diego",es:"Sí, el sábado abrimos a las nueve. Hasta luego.",pt:"Sim, no sábado abrimos às nove. Até logo."}],X=[{es:"¿Cuánto sale el kilo de manzanas?",opcoes:["Catorce pesos","Cuarenta pesos","Cuatro pesos","Cien pesos"],correta:1,pt:"Quanto custa o quilo de maçãs?"},{es:"¿Cuántos kilos compra Ana?",opcoes:["Dos kilos","Un kilo","Tres kilos","Cinco kilos"],correta:0,pt:"Quantos quilos a Ana compra?"},{es:"¿Cuánto es en total?",opcoes:["Ochenta pesos","Cien pesos","Veinte pesos","Cuarenta pesos"],correta:0,pt:"Quanto é no total?"},{es:"¿Cuánto vuelto recibe Ana?",opcoes:["Cien pesos","Ochenta pesos","Veinte pesos","Diez pesos"],correta:2,pt:"Quanto de troco a Ana recebe?"},{es:"¿A qué hora cierra la feria?",opcoes:["A las seis","A las nueve","A las diez","A las ocho de la noche"],correta:3,pt:"A que horas a feira fecha?"},{es:"¿A qué hora abren el sábado?",opcoes:["A las ocho","A las nueve","A las siete","A las diez"],correta:1,pt:"A que horas eles abrem no sábado?"}],Z={id:x,nivel:I,titulo:F,subtitulo:R,introAudioKey:G,introPt:J,cenario:w,dialogo:W,perguntas:X},_="q-b03",ee="basico",oe="Quiz — Direções e transporte",ae="Escute a conversa e responda em espanhol",se="q-b03-i",ne="Hora do quiz! Escute esta conversa na rua, alguém pedindo informação pra chegar a um lugar. Pode ouvir quantas vezes quiser e depois responda às perguntas em espanhol.",ie="Um turista perdido pede direções e informação sobre o ônibus.",re=[{audioKey:"q-b03-d1",voz:"Diego",es:"Disculpe, estoy perdido. ¿Me puede ayudar?",pt:"Com licença, estou perdido. Pode me ajudar?"},{audioKey:"q-b03-d2",voz:"Ana",es:"Sí, claro. ¿Adónde querés ir?",pt:"Sim, claro. Aonde você quer ir?"},{audioKey:"q-b03-d3",voz:"Diego",es:"Al centro. ¿Cómo llego?",pt:"Ao centro. Como eu chego?"},{audioKey:"q-b03-d4",voz:"Ana",es:"Seguí derecho y doblá a la izquierda en la esquina.",pt:"Siga reto e vire à esquerda na esquina."},{audioKey:"q-b03-d5",voz:"Diego",es:"¿Está cerca o está lejos?",pt:"Está perto ou está longe?"},{audioKey:"q-b03-d6",voz:"Ana",es:"Está un poco lejos. Mejor tomá el colectivo.",pt:"Está um pouco longe. Melhor pegar o ônibus."},{audioKey:"q-b03-d7",voz:"Diego",es:"¿Dónde está la parada?",pt:"Onde fica o ponto?"},{audioKey:"q-b03-d8",voz:"Ana",es:"A la derecha, a dos cuadras. El número doce va al centro.",pt:"À direita, a dois quarteirões. O número doze vai ao centro."},{audioKey:"q-b03-d9",voz:"Diego",es:"¿Y cuánto sale hasta el centro?",pt:"E quanto custa até o centro?"},{audioKey:"q-b03-d10",voz:"Ana",es:"Sale treinta pesos. ¡Buen viaje!",pt:"Custa trinta pesos. Boa viagem!"}],te=[{es:"¿Qué problema tiene Diego al principio?",opcoes:["Tiene hambre","Está perdido","Perdió la plata","Está cansado"],correta:1,pt:"Qual problema o Diego tem no começo?"},{es:"¿Adónde quiere ir Diego?",opcoes:["A la playa","Al hotel","Al centro","Al aeropuerto"],correta:2,pt:"Aonde o Diego quer ir?"},{es:"¿Hacia qué lado tiene que doblar en la esquina?",opcoes:["A la izquierda","A la derecha","Para atrás","Sigue derecho"],correta:0,pt:"Para que lado ele tem que virar na esquina?"},{es:"¿El centro está cerca o lejos?",opcoes:["Muy cerca","En la esquina","Un poco lejos","Al lado"],correta:2,pt:"O centro está perto ou longe?"},{es:"¿Qué transporte le recomienda Ana?",opcoes:["El subte","Un taxi","Ir caminando","El colectivo"],correta:3,pt:"Qual transporte a Ana recomenda?"},{es:"¿Cuánto sale el viaje hasta el centro?",opcoes:["Trece pesos","Treinta pesos","Doce pesos","Veinte pesos"],correta:1,pt:"Quanto custa a viagem até o centro?"}],ue={id:_,nivel:ee,titulo:oe,subtitulo:ae,introAudioKey:se,introPt:ne,cenario:ie,dialogo:re,perguntas:te},de="q-b04",ce="basico",le="Quiz — Restaurante: chegar e pedir",pe="Escute a conversa e responda em espanhol",me="q-b04-i",ve="Hora do quiz! Escute este casal chegando num restaurante e fazendo o pedido com a garçonete. Pode ouvir quantas vezes quiser e depois responda às perguntas em espanhol.",qe="Um casal chega num restaurante, consegue mesa e faz o pedido.",ge=[{audioKey:"q-b04-d1",voz:"Diego",es:"Buenas noches. ¿Tienen una mesa para dos?",pt:"Boa noite. Vocês têm uma mesa pra dois?"},{audioKey:"q-b04-d2",voz:"Ana",es:"Sí, claro. ¿Adentro o afuera?",pt:"Sim, claro. Dentro ou fora?"},{audioKey:"q-b04-d3",voz:"Diego",es:"Afuera, por favor. ¿Me trae la carta?",pt:"Fora, por favor. Pode me trazer o cardápio?"},{audioKey:"q-b04-d4",voz:"Ana",es:"Acá tiene. ¿Qué van a tomar?",pt:"Aqui está. O que vão beber?"},{audioKey:"q-b04-d5",voz:"Diego",es:"Para mí, una copa de vino tinto. ¿Qué nos recomienda?",pt:"Pra mim, uma taça de vinho tinto. O que você recomenda pra gente?"},{audioKey:"q-b04-d6",voz:"Ana",es:"La milanesa está muy rica hoy.",pt:"A milanesa está muito gostosa hoje."},{audioKey:"q-b04-d7",voz:"Diego",es:"Perfecto. De entrada, una empanada, y de principal, la milanesa.",pt:"Perfeito. De entrada, uma empanada, e de principal, a milanesa."},{audioKey:"q-b04-d8",voz:"Ana",es:"Muy bien. ¿Algo más para tomar?",pt:"Muito bem. Mais alguma coisa pra beber?"},{audioKey:"q-b04-d9",voz:"Diego",es:"Un vaso de agua sin gas, por favor. Nada más, gracias.",pt:"Um copo de água sem gás, por favor. Só isso, obrigado."},{audioKey:"q-b04-d10",voz:"Ana",es:"Enseguida se lo traigo.",pt:"Já trago pra você."}],be=[{es:"¿Para cuántas personas es la mesa?",opcoes:["Para una","Para dos","Para tres","Para cuatro"],correta:1,pt:"Para quantas pessoas é a mesa?"},{es:"¿Dónde se quieren sentar?",opcoes:["Afuera","Adentro","En la barra","Cerca de la puerta"],correta:0,pt:"Onde eles querem se sentar?"},{es:"¿Qué pide para tomar al principio?",opcoes:["Una cerveza","Un café","Una copa de vino tinto","Un jugo"],correta:2,pt:"O que ele pede para beber no começo?"},{es:"¿Qué le recomienda la moza?",opcoes:["El asado","El pescado","Las empanadas","La milanesa"],correta:3,pt:"O que a garçonete recomenda?"},{es:"¿Qué pide de entrada?",opcoes:["Una empanada","Una ensalada","Una sopa","Una provoleta"],correta:0,pt:"O que ele pede de entrada?"},{es:"¿Cómo pide el agua?",opcoes:["Con gas","Sin gas","Con limón","Bien fría"],correta:1,pt:"Como ele pede a água?"}],Ae={id:de,nivel:ce,titulo:le,subtitulo:pe,introAudioKey:me,introPt:ve,cenario:qe,dialogo:ge,perguntas:be},he="q-b05",ze="basico",ye="Quiz — A parrilla",fe="Escute a conversa e responda em espanhol",De="q-b05-i",Ke="Hora do quiz! Escute este casal numa parrilla, escolhendo os cortes, o ponto da carne e a sobremesa. Pode ouvir quantas vezes quiser e depois responda às perguntas em espanhol.",Ee="Um casal pede churrasco numa parrilla e fecha com sobremesa.",Pe=[{audioKey:"q-b05-d1",voz:"Ana",es:"¿Ya saben qué van a pedir?",pt:"Já sabem o que vão pedir?"},{audioKey:"q-b05-d2",voz:"Diego",es:"Sí. Para mí, un bife de chorizo. ¿Qué me recomienda?",pt:"Sim. Pra mim, um bife de chorizo. O que você me recomenda?"},{audioKey:"q-b05-d3",voz:"Ana",es:"El vacío está muy bueno hoy. ¿Cómo lo quiere el bife?",pt:"O vacío está muito bom hoje. Como o senhor quer o bife?"},{audioKey:"q-b05-d4",voz:"Diego",es:"Lo quiero a punto, por favor. No me gusta bien cocido.",pt:"Eu quero ao ponto, por favor. Não gosto bem passado."},{audioKey:"q-b05-d5",voz:"Ana",es:"Perfecto. ¿Y de entrada? Tenemos provoleta.",pt:"Perfeito. E de entrada? Temos provoleta."},{audioKey:"q-b05-d6",voz:"Diego",es:"Una provoleta, dale. Y unas papas fritas para acompañar.",pt:"Uma provoleta, pode ser. E umas batatas fritas pra acompanhar."},{audioKey:"q-b05-d7",voz:"Ana",es:"Muy bien. ¿Algo sin carne? ¿Hay alguien vegetariano?",pt:"Muito bem. Algo sem carne? Tem alguém vegetariano?"},{audioKey:"q-b05-d8",voz:"Diego",es:"Mi esposa es vegetariana. Para ella, una ensalada sin cebolla.",pt:"Minha esposa é vegetariana. Pra ela, uma salada sem cebola."},{audioKey:"q-b05-d9",voz:"Ana",es:"Anotado. ¿Van a querer postre?",pt:"Anotado. Vão querer sobremesa?"},{audioKey:"q-b05-d10",voz:"Diego",es:"Sí, de postre un flan con dulce de leche. ¡Gracias!",pt:"Sim, de sobremesa um pudim com doce de leite. Obrigado!"}],Qe=[{es:"¿Qué corte pide Diego para él?",opcoes:["El vacío","Un bife de chorizo","Asado de tira","Una milanesa"],correta:1,pt:"Que corte o Diego pede pra ele?"},{es:"¿Qué corte le recomienda la moza?",opcoes:["El vacío","El bife de chorizo","La provoleta","El pescado"],correta:0,pt:"Que corte a garçonete recomenda?"},{es:"¿Cómo quiere la carne?",opcoes:["Jugosa","Bien cocida","A punto","Cruda"],correta:2,pt:"Como ele quer a carne?"},{es:"¿Qué pide de entrada?",opcoes:["Una empanada","Una ensalada","Papas fritas","Una provoleta"],correta:3,pt:"O que ele pede de entrada?"},{es:"¿Qué pide para su esposa?",opcoes:["Una ensalada sin cebolla","Un bife","Una milanesa","Pescado"],correta:0,pt:"O que ele pede para a esposa dele?"},{es:"¿Qué postre pide?",opcoes:["Un helado","Un café con leche","Un flan con dulce de leche","Una fruta"],correta:2,pt:"Que sobremesa ele pede?"}],$e={id:he,nivel:ze,titulo:ye,subtitulo:fe,introAudioKey:De,introPt:Ke,cenario:Ee,dialogo:Pe,perguntas:Qe},Ce="q-b06",je="basico",Se="Quiz — Compras: roupa e tamanhos",Oe="Escute a conversa e responda em espanhol",Ue="q-b06-i",Ne="Agora um teste rápido! Escute o casal numa loja de roupa e responda às perguntas em espanhol. Pode ouvir a conversa quantas vezes quiser.",Me="Numa loja de roupa, Diego procura uma camiseta e fala com a vendedora Ana sobre tamanho, prova e preço.",Be=[{audioKey:"q-b06-d1",voz:"Ana",es:"Hola, ¿te puedo ayudar?",pt:"Oi, posso ajudar?"},{audioKey:"q-b06-d2",voz:"Diego",es:"Sí, gracias. Estoy buscando una remera azul.",pt:"Sim, obrigado. Estou procurando uma camiseta azul."},{audioKey:"q-b06-d3",voz:"Ana",es:"Tenemos varias. ¿Qué talle buscás?",pt:"Temos várias. Que tamanho você procura?"},{audioKey:"q-b06-d4",voz:"Diego",es:"Talle mediano. ¿Puedo probármelo?",pt:"Tamanho médio. Posso provar?"},{audioKey:"q-b06-d5",voz:"Ana",es:"Claro, el probador está al fondo.",pt:"Claro, o provador é lá no fundo."},{audioKey:"q-b06-d6",voz:"Diego",es:"Me queda un poco grande. ¿Tenés un talle más chico?",pt:"Ficou um pouco grande. Você tem um tamanho menor?"},{audioKey:"q-b06-d7",voz:"Ana",es:"Sí, acá tenés. Este te queda mejor.",pt:"Sim, aqui está. Esse fica melhor em você."},{audioKey:"q-b06-d8",voz:"Diego",es:"Me queda bien. ¿Cuánto sale?",pt:"Ficou bom. Quanto custa?"},{audioKey:"q-b06-d9",voz:"Ana",es:"Mil pesos. Podés pagar en cuotas si querés.",pt:"Mil pesos. Pode pagar parcelado se quiser."},{audioKey:"q-b06-d10",voz:"Diego",es:"Dale, me la llevo. ¡Gracias!",pt:"Beleza, vou levar. Obrigado!"}],Te=[{es:"¿Qué está buscando Diego?",opcoes:["Un pantalón negro","Una remera azul","Un vestido rojo","Una campera"],correta:1,pt:"O que Diego está procurando?"},{es:"¿Qué talle pide Diego al principio?",opcoes:["Chico","Grande","Mediano","Extra grande"],correta:2,pt:"Que tamanho Diego pede no começo?"},{es:"¿Por qué pide otro talle?",opcoes:["Le queda grande","Le queda chico","No le gusta el color","Es muy caro"],correta:0,pt:"Por que ele pede outro tamanho?"},{es:"¿Cuánto sale la remera?",opcoes:["Cien pesos","Quinientos pesos","Dos mil pesos","Mil pesos"],correta:3,pt:"Quanto custa a camiseta?"},{es:"¿Cómo puede pagar, según Ana?",opcoes:["En cuotas","Solo en efectivo","Con un descuento","Solo con tarjeta"],correta:0,pt:"Como ele pode pagar, segundo Ana?"},{es:"Al final, ¿qué decide Diego?",opcoes:["No comprar nada","Cambiar de tienda","Probarse un pantalón","Llevarse la remera"],correta:3,pt:"No fim, o que Diego decide?"}],Ve={id:Ce,nivel:je,titulo:Se,subtitulo:Oe,introAudioKey:Ue,introPt:Ne,cenario:Me,dialogo:Be,perguntas:Te},Le="q-b07",He="basico",Ye="Quiz — Hotel: check-in e problemas",ke="Escute a conversa e responda em espanhol",xe="q-b07-i",Ie="Vamos testar o hotel! Escute o casal na recepção e responda em espanhol. Pode ouvir a conversa quantas vezes quiser.",Fe="Diego chega num hotel, faz o check-in com a recepcionista Ana e depois relata um problema no quarto.",Re=[{audioKey:"q-b07-d1",voz:"Diego",es:"Buenas tardes, tengo una reserva a nombre de Diego.",pt:"Boa tarde, tenho uma reserva em nome de Diego."},{audioKey:"q-b07-d2",voz:"Ana",es:"Perfecto. Es una habitación doble, ¿verdad?",pt:"Perfeito. É um quarto de casal, certo?"},{audioKey:"q-b07-d3",voz:"Diego",es:"Sí. ¿Incluye el desayuno?",pt:"Sim. Inclui o café da manhã?"},{audioKey:"q-b07-d4",voz:"Ana",es:"Sí, el desayuno es de ocho a diez. Acá tenés la llave.",pt:"Sim, o café é das oito às dez. Aqui está a chave."},{audioKey:"q-b07-d5",voz:"Diego",es:"Gracias. ¿Cuál es la contraseña del wifi?",pt:"Obrigado. Qual é a senha do wifi?"},{audioKey:"q-b07-d6",voz:"Ana",es:"Es hotel2026, todo junto.",pt:"É hotel2026, tudo junto."},{audioKey:"q-b07-d7",voz:"Diego",es:"Disculpá, subí al cuarto y no funciona el aire.",pt:"Desculpa, subi ao quarto e o ar não funciona."},{audioKey:"q-b07-d8",voz:"Ana",es:"Perdón, ya mando a alguien. ¿Algo más?",pt:"Desculpe, já mando alguém. Mais alguma coisa?"},{audioKey:"q-b07-d9",voz:"Diego",es:"Sí, falta una toalla. ¿Me pueden traer una?",pt:"Sim, falta uma toalha. Podem me trazer uma?"},{audioKey:"q-b07-d10",voz:"Ana",es:"Por supuesto, en un rato se la llevamos.",pt:"Claro, num instante levamos."}],Ge=[{es:"¿Qué tipo de habitación reservó Diego?",opcoes:["Individual","Doble","Triple","Una suite"],correta:1,pt:"Que tipo de quarto Diego reservou?"},{es:"¿A qué hora es el desayuno?",opcoes:["De siete a nueve","De ocho a diez","De nueve a once","De seis a ocho"],correta:1,pt:"A que horas é o café da manhã?"},{es:"¿Qué le pide Diego a Ana después de la llave?",opcoes:["La factura","Un taxi","La contraseña del wifi","El check-out"],correta:2,pt:"O que Diego pede a Ana depois da chave?"},{es:"¿Cuál es el problema en el cuarto?",opcoes:["No hay agua caliente","No funciona la ducha","No funciona el aire","Falta la llave"],correta:2,pt:"Qual é o problema no quarto?"},{es:"¿Qué más le falta a Diego?",opcoes:["Una toalla","Una sábana","Una almohada","El control"],correta:0,pt:"O que mais falta para Diego?"},{es:"¿Qué responde Ana sobre el problema del aire?",opcoes:["Que no se puede arreglar","Que ya manda a alguien","Que cambie de cuarto","Que pague más"],correta:1,pt:"O que Ana responde sobre o problema do ar?"}],Je={id:Le,nivel:He,titulo:Ye,subtitulo:ke,introAudioKey:xe,introPt:Ie,cenario:Fe,dialogo:Re,perguntas:Ge},we="q-b08",We="basico",Xe="Quiz — Mercado e farmácia",Ze="Escute a conversa e responda em espanhol",_e="q-b08-i",eo="Hora do mercado e da farmácia! Escute as conversas e responda em espanhol. Pode ouvir quantas vezes quiser.",oo="Primeiro Diego compra frutas e ovos no mercado; depois vai à farmácia porque está com dor de cabeça.",ao=[{audioKey:"q-b08-d1",voz:"Ana",es:"Hola, ¿qué va a llevar?",pt:"Oi, o que vai levar?"},{audioKey:"q-b08-d2",voz:"Diego",es:"Necesito un kilo de manzanas y una docena de huevos.",pt:"Preciso de um quilo de maçãs e uma dúzia de ovos."},{audioKey:"q-b08-d3",voz:"Ana",es:"Listo. ¿Algo más?",pt:"Pronto. Mais alguma coisa?"},{audioKey:"q-b08-d4",voz:"Diego",es:"¿Cuánto cuesta el kilo de tomates?",pt:"Quanto custa o quilo de tomates?"},{audioKey:"q-b08-d5",voz:"Ana",es:"Doscientos pesos el kilo.",pt:"Duzentos pesos o quilo."},{audioKey:"q-b08-d6",voz:"Diego",es:"Medio kilo, nada más. ¿Me da una bolsa?",pt:"Meio quilo, só isso. Pode me dar uma sacola?"},{audioKey:"q-b08-d7",voz:"Ana",es:"Acá tenés. ¡Buen provecho!",pt:"Aqui está. Bom apetite!"},{audioKey:"q-b08-d8",voz:"Diego",es:"Gracias. Ahora voy a la farmacia, me duele la cabeza.",pt:"Obrigado. Agora vou à farmácia, estou com dor de cabeça."},{audioKey:"q-b08-d9",voz:"Ana",es:"¿Tenés algo para el dolor en casa?",pt:"Você tem algo pra dor em casa?"},{audioKey:"q-b08-d10",voz:"Diego",es:"No, voy a pedir un ibuprofeno. ¿Necesito receta?",pt:"Não, vou pedir um ibuprofeno. Preciso de receita?"}],so=[{es:"¿Cuántos huevos pide Diego?",opcoes:["Medio kilo","Una docena","Un kilo","Seis"],correta:1,pt:"Quantos ovos Diego pede?"},{es:"¿Cuánto cuesta el kilo de tomates?",opcoes:["Cien pesos","Mil pesos","Doscientos pesos","Cincuenta pesos"],correta:2,pt:"Quanto custa o quilo de tomates?"},{es:"¿Qué cantidad de tomates lleva al final?",opcoes:["Un kilo","Dos kilos","Una docena","Medio kilo"],correta:3,pt:"Que quantidade de tomates ele leva no fim?"},{es:"¿Qué le pide Diego a Ana en la caja?",opcoes:["Una bolsa","Un descuento","Una receta","Un ticket"],correta:0,pt:"O que Diego pede a Ana no caixa?"},{es:"¿Por qué va Diego a la farmacia?",opcoes:["Le duele el estómago","Le duele la cabeza","Está constipado","Necesita protector solar"],correta:1,pt:"Por que Diego vai à farmácia?"},{es:"¿Qué quiere comprar en la farmacia?",opcoes:["Aspirina","Protector solar","Ibuprofeno","Repelente"],correta:2,pt:"O que ele quer comprar na farmácia?"}],no={id:we,nivel:We,titulo:Xe,subtitulo:Ze,introAudioKey:_e,introPt:eo,cenario:oo,dialogo:ao,perguntas:so},io="q-b09",ro="basico",to="Quiz — Falsos amigos",uo="Escute a conversa e responda em espanhol",co="q-b09-i",lo="Cuidado com as armadilhas! Escute essa conversa cheia de falsos amigos e responda pelo sentido CORRETO em espanhol. Pode ouvir quantas vezes quiser.",po="Ana e Diego conversam num jantar e um falso amigo causa uma confusão engraçada: Diego acha que Ana disse que está grávida.",mo=[{audioKey:"q-b09-d1",voz:"Ana",es:"Diego, ¡qué rica esta comida! Está exquisita.",pt:"Diego, que gostosa essa comida! Está deliciosa."},{audioKey:"q-b09-d2",voz:"Diego",es:"¿Exquisita? ¿Querés decir que está rara?",pt:"Exquisita? Você quer dizer que está esquisita?"},{audioKey:"q-b09-d3",voz:"Ana",es:"¡No, tonto! Exquisita quiere decir deliciosa. Me encanta.",pt:"Não, bobo! Exquisita quer dizer deliciosa. Adoro."},{audioKey:"q-b09-d4",voz:"Diego",es:"Ah, claro. Pasame un vaso, por favor, tengo sed.",pt:"Ah, claro. Me passa um copo, por favor, estou com sede."},{audioKey:"q-b09-d5",voz:"Ana",es:"Tomá. Che, hoy estuve embarazada todo el día.",pt:"Toma. Olha, hoje fiquei embarazada o dia todo."},{audioKey:"q-b09-d6",voz:"Diego",es:"¿¿Embarazada?? ¿Vamos a tener un bebé?",pt:"Grávida?? Vamos ter um bebê?"},{audioKey:"q-b09-d7",voz:"Ana",es:"¡No, no! Embarazada es grávida. Yo quise decir avergonzada, con vergüenza.",pt:"Não, não! Embarazada é grávida. Eu quis dizer envergonhada."},{audioKey:"q-b09-d8",voz:"Diego",es:"¡Uf, qué susto! Entonces hoy pasaste vergüenza en la oficina.",pt:"Ufa, que susto! Então hoje você passou vergonha no escritório."},{audioKey:"q-b09-d9",voz:"Ana",es:"Exacto. Esperá un rato y te cuento todo.",pt:"Exato. Espera um instante e te conto tudo."},{audioKey:"q-b09-d10",voz:"Diego",es:"Dale. Todavía tenemos tiempo antes de la cena de mañana.",pt:"Beleza. Ainda temos tempo antes do jantar de amanhã."}],vo=[{es:'Cuando Ana dice que la comida está "exquisita", quiere decir que está…',opcoes:["Rara","Deliciosa","Fría","Salada"],correta:1,pt:"Quando Ana diz que a comida está 'exquisita', ela quer dizer que está…"},{es:"¿Qué le pide Diego a Ana para tomar agua?",opcoes:["Una taza","Una botella","Un vaso","Un plato"],correta:2,pt:"O que Diego pede a Ana para beber água?"},{es:'En español, "embarazada" significa…',opcoes:["Avergonzada","Grávida","Cansada","Enojada"],correta:1,pt:"Em espanhol, 'embarazada' significa…"},{es:"¿Qué quería decir Ana en realidad?",opcoes:["Que estaba grávida","Que estaba avergonzada","Que estaba enferma","Que estaba apurada"],correta:1,pt:"O que Ana queria dizer na verdade?"},{es:"¿Dónde pasó vergüenza Ana?",opcoes:["En el taller mecánico","En casa","En la oficina","En la cena"],correta:2,pt:"Onde Ana passou vergonha?"},{es:'Cuando Diego dice "todavía tenemos tiempo", quiere decir que…',opcoes:["Aún tienen tiempo","No tienen tiempo","Contudo, tienen tiempo","Perdieron el tiempo"],correta:0,pt:"Quando Diego diz 'todavía tenemos tiempo', ele quer dizer que…"}],qo={id:io,nivel:ro,titulo:to,subtitulo:uo,introAudioKey:co,introPt:lo,cenario:po,dialogo:mo,perguntas:vo},go="q-i01",bo="intermediario",Ao="Quiz — Falar do passado",ho="Escute a conversa e responda em espanhol",zo="q-i01-i",yo="Escute a Ana e o Diego conversando sobre o fim de semana e responda às perguntas em espanhol. Pode ouvir quantas vezes quiser, sem pressa.",fo="Segunda-feira de manhã. A Ana pergunta ao Diego o que ele fez no fim de semana.",Do=[{audioKey:"q-i01-d1",voz:"Ana",es:"¡Hola, Diego! ¿Qué hiciste el finde?",pt:"Oi, Diego! O que você fez no fim de semana?"},{audioKey:"q-i01-d2",voz:"Diego",es:"¡Hola! El sábado fui a Colonia con unos amigos.",pt:"Oi! No sábado fui a Colônia com uns amigos."},{audioKey:"q-i01-d3",voz:"Ana",es:"¡Qué bueno! ¿Y cómo estuvo?",pt:"Que legal! E como foi?"},{audioKey:"q-i01-d4",voz:"Diego",es:"Estuvo bárbaro. Caminamos mucho y sacamos un montón de fotos.",pt:"Foi ótimo. Caminhamos muito e tiramos um montão de fotos."},{audioKey:"q-i01-d5",voz:"Ana",es:"¿Y comieron algo rico?",pt:"E comeram algo gostoso?"},{audioKey:"q-i01-d6",voz:"Diego",es:"Sí, comimos pescado en un restaurante frente al río. La pasamos bárbaro.",pt:"Sim, comemos peixe num restaurante de frente pro rio. Foi ótimo."},{audioKey:"q-i01-d7",voz:"Ana",es:"Me encanta Colonia. ¿Te quedaste a dormir allá?",pt:"Adoro Colônia. Você ficou pra dormir lá?"},{audioKey:"q-i01-d8",voz:"Diego",es:"No, volvimos el mismo día. ¿Y vos? ¿Qué hiciste?",pt:"Não, voltamos no mesmo dia. E você? O que fez?"},{audioKey:"q-i01-d9",voz:"Ana",es:"Yo me quedé en casa, pero el domingo visité un museo.",pt:"Eu fiquei em casa, mas no domingo visitei um museu."},{audioKey:"q-i01-d10",voz:"Diego",es:"¡Qué bien! ¿Te gustó?",pt:"Que bom! Você gostou?"}],Ko=[{es:"¿Adónde fue Diego el sábado?",opcoes:["A la playa","A Colonia","A un museo","Al centro"],correta:1,pt:"Aonde o Diego foi no sábado?"},{es:"¿Con quién fue Diego?",opcoes:["Con unos amigos","Solo","Con su familia","Con Ana"],correta:0,pt:"Com quem o Diego foi?"},{es:"¿Qué comieron en el restaurante?",opcoes:["Carne","Pizza","Pescado","Pasta"],correta:2,pt:"O que eles comeram no restaurante?"},{es:"¿Se quedó Diego a dormir en Colonia?",opcoes:["Sí, dos días","Sí, una noche","No sabemos","No, volvió el mismo día"],correta:3,pt:"O Diego ficou pra dormir em Colônia?"},{es:"¿Qué hizo Ana el domingo?",opcoes:["Visitó un museo","Fue a la playa","Viajó a Colonia","Sacó fotos"],correta:0,pt:"O que a Ana fez no domingo?"},{es:"¿Cómo le pareció el paseo a Diego?",opcoes:["Más o menos","Aburrido","Estuvo bárbaro","No le gustó"],correta:2,pt:"O que o Diego achou do passeio?"}],Eo={id:go,nivel:bo,titulo:Ao,subtitulo:ho,introAudioKey:zo,introPt:yo,cenario:fo,dialogo:Do,perguntas:Ko},Po="q-i02",Qo="intermediario",$o="Quiz — Rotina e como era antes",Co="Escute a conversa e responda em espanhol",jo="q-i02-i",So="Escute a Ana e o Diego falando da rotina deles e de como era a vida antes, e responda em espanhol. Pode ouvir quantas vezes quiser, com calma.",Oo="A Ana e o Diego conversam sobre o dia a dia de hoje e comparam com a infância.",Uo=[{audioKey:"q-i02-d1",voz:"Ana",es:"Diego, ¿a qué hora te levantás durante la semana?",pt:"Diego, a que horas você se levanta durante a semana?"},{audioKey:"q-i02-d2",voz:"Diego",es:"Me levanto a las siete, me ducho y desayuno un café.",pt:"Me levanto às sete, tomo banho e tomo um café."},{audioKey:"q-i02-d3",voz:"Ana",es:"Yo me levanto más tarde, pero me acuesto muy tarde también.",pt:"Eu me levanto mais tarde, mas me deito muito tarde também."},{audioKey:"q-i02-d4",voz:"Diego",es:"Antes era distinto. De chico me acostaba temprano.",pt:"Antes era diferente. Quando criança eu me deitava cedo."},{audioKey:"q-i02-d5",voz:"Ana",es:"¡Yo igual! Antes vivía en São Paulo y tenía un perro.",pt:"Eu também! Antes morava em São Paulo e tinha um cachorro."},{audioKey:"q-i02-d6",voz:"Diego",es:"Qué lindo. ¿Y cómo era tu barrio?",pt:"Que bonito. E como era o seu bairro?"},{audioKey:"q-i02-d7",voz:"Ana",es:"Había mucha gente en la calle y los chicos jugaban afuera.",pt:"Tinha muita gente na rua e as crianças brincavam na rua."},{audioKey:"q-i02-d8",voz:"Diego",es:"De chico yo iba a la playa todos los veranos.",pt:"Quando criança eu ia à praia todos os verões."},{audioKey:"q-i02-d9",voz:"Ana",es:"¡Qué suerte! Ahora trabajo mucho y casi no salgo.",pt:"Que sorte! Agora trabalho muito e quase não saio."},{audioKey:"q-i02-d10",voz:"Diego",es:"Sí, antes teníamos más tiempo libre.",pt:"É, antes a gente tinha mais tempo livre."}],No=[{es:"¿A qué hora se levanta Diego durante la semana?",opcoes:["A las ocho","A las seis","A las siete","A las nueve"],correta:2,pt:"A que horas o Diego se levanta durante a semana?"},{es:"¿Qué hace Ana muy tarde?",opcoes:["Se acuesta","Almuerza","Se ducha","Desayuna"],correta:0,pt:"O que a Ana faz muito tarde?"},{es:"¿Dónde vivía Ana antes?",opcoes:["En Colonia","En la playa","En Montevideo","En São Paulo"],correta:3,pt:"Onde a Ana morava antes?"},{es:"¿Qué tenía Ana de chica?",opcoes:["Un gato","Un perro","Una bici","Un caballo"],correta:1,pt:"O que a Ana tinha quando criança?"},{es:"¿Qué hacía Diego de chico todos los veranos?",opcoes:["Trabajaba","Estudiaba","Iba a la playa","Viajaba al exterior"],correta:2,pt:"O que o Diego fazia quando criança todos os verões?"},{es:"¿Por qué casi no sale Ana ahora?",opcoes:["Porque trabaja mucho","Porque está enferma","Porque no le gusta","Porque llueve"],correta:0,pt:"Por que a Ana quase não sai agora?"}],Mo={id:Po,nivel:Qo,titulo:$o,subtitulo:Co,introAudioKey:jo,introPt:So,cenario:Oo,dialogo:Uo,perguntas:No},Bo="q-i03",To="intermediario",Vo="Quiz — Planos e futuro",Lo="Escute a conversa e responda em espanhol",Ho="q-i03-i",Yo="Escute a Ana e o Diego fazendo planos e combinando um encontro, e responda em espanhol. Pode ouvir quantas vezes quiser, sem pressa.",ko="A Ana e o Diego falam do que vão fazer e combinam de sair juntos.",xo=[{audioKey:"q-i03-d1",voz:"Ana",es:"Diego, ¿qué vas a hacer el finde que viene?",pt:"Diego, o que você vai fazer no fim de semana que vem?"},{audioKey:"q-i03-d2",voz:"Diego",es:"Voy a viajar a Colonia con mi hermano.",pt:"Vou viajar a Colônia com meu irmão."},{audioKey:"q-i03-d3",voz:"Ana",es:"¡Qué bueno! ¿Y esta semana?",pt:"Que bom! E esta semana?"},{audioKey:"q-i03-d4",voz:"Diego",es:"Esta noche voy a comer afuera, pero mañana estoy libre.",pt:"Hoje à noite vou comer fora, mas amanhã estou livre."},{audioKey:"q-i03-d5",voz:"Ana",es:"¿Quedamos mañana a las ocho para tomar un café?",pt:"Combinamos amanhã às oito pra tomar um café?"},{audioKey:"q-i03-d6",voz:"Diego",es:"¡Dale! ¿En la plaza, te parece?",pt:"Combinado! Na praça, topa?"},{audioKey:"q-i03-d7",voz:"Ana",es:"Perfecto. Después quiero ver la muestra de fotos del museo.",pt:"Perfeito. Depois quero ver a exposição de fotos do museu."},{audioKey:"q-i03-d8",voz:"Diego",es:"Buenísimo. Vamos a pasear un rato y después al museo.",pt:"Ótimo. Vamos passear um pouco e depois ao museu."},{audioKey:"q-i03-d9",voz:"Ana",es:"¡Dale! Entonces nos vemos mañana a las ocho.",pt:"Beleza! Então a gente se vê amanhã às oito."},{audioKey:"q-i03-d10",voz:"Diego",es:"Nos vemos. ¡Hasta mañana!",pt:"A gente se vê. Até amanhã!"}],Io=[{es:"¿Qué va a hacer Diego el finde que viene?",opcoes:["Quedarse en casa","Viajar a Colonia","Ir al museo","Trabajar"],correta:1,pt:"O que o Diego vai fazer no fim de semana que vem?"},{es:"¿Con quién va a viajar Diego?",opcoes:["Con Ana","Con un amigo","Con su hermano","Solo"],correta:2,pt:"Com quem o Diego vai viajar?"},{es:"¿Qué va a hacer Diego esta noche?",opcoes:["Comer afuera","Quedarse en casa","Ir al museo","Viajar"],correta:0,pt:"O que o Diego vai fazer hoje à noite?"},{es:"¿A qué hora quedan mañana?",opcoes:["A las siete","A las nueve","A las seis","A las ocho"],correta:3,pt:"A que horas eles combinam de se ver amanhã?"},{es:"¿Dónde se van a encontrar?",opcoes:["En la plaza","En el museo","En un café","En la playa"],correta:0,pt:"Onde eles vão se encontrar?"},{es:"¿Qué quiere ver Ana después del café?",opcoes:["Una película","La muestra de fotos del museo","El río","Un partido"],correta:1,pt:"O que a Ana quer ver depois do café?"}],Fo={id:Bo,nivel:To,titulo:Vo,subtitulo:Lo,introAudioKey:Ho,introPt:Yo,cenario:ko,dialogo:xo,perguntas:Io},Ro="q-i04",Go="intermediario",Jo="Quiz — Saúde e emergências",wo="Escute a conversa e responda em espanhol",Wo="q-i04-i",Xo="Escute a Ana e o Diego numa situação de saúde e responda em espanhol. Pode ouvir quantas vezes quiser, com calma.",Zo="O Diego não se sente bem e a Ana o ajuda a procurar atendimento.",_o=[{audioKey:"q-i04-d1",voz:"Ana",es:"Diego, ¿qué te pasa? Estás pálido.",pt:"Diego, o que você tem? Você está pálido."},{audioKey:"q-i04-d2",voz:"Diego",es:"No me siento bien. Tengo fiebre y me duele la cabeza.",pt:"Não me sinto bem. Estou com febre e me dói a cabeça."},{audioKey:"q-i04-d3",voz:"Ana",es:"¿Tenés náuseas o estás mareado?",pt:"Você está enjoado ou tonto?"},{audioKey:"q-i04-d4",voz:"Diego",es:"Estoy un poco mareado. Y antes me torcí el tobillo en la escalera.",pt:"Estou um pouco tonto. E antes torci o tornozelo na escada."},{audioKey:"q-i04-d5",voz:"Ana",es:"Uy. Necesitás un médico. ¿Dónde hay un hospital cerca?",pt:"Eita. Você precisa de um médico. Onde tem um hospital perto?"},{audioKey:"q-i04-d6",voz:"Diego",es:"Hay uno a tres cuadras, pero no puedo caminar bien.",pt:"Tem um a três quarteirões, mas não consigo caminhar bem."},{audioKey:"q-i04-d7",voz:"Ana",es:"Quedate tranquilo. Voy a llamar a una ambulancia.",pt:"Fica tranquilo. Vou chamar uma ambulância."},{audioKey:"q-i04-d8",voz:"Diego",es:"Gracias. ¿Tenés algo para el dolor mientras tanto?",pt:"Obrigado. Você tem algo pra dor enquanto isso?"},{audioKey:"q-i04-d9",voz:"Ana",es:"Sí, una pastilla. ¿Cada cuánto la tomás normalmente?",pt:"Tenho, um comprimido. De quanto em quanto tempo você toma normalmente?"},{audioKey:"q-i04-d10",voz:"Diego",es:"Cada ocho horas. Ya me siento un poco mejor, gracias.",pt:"De oito em oito horas. Já me sinto um pouco melhor, obrigado."}],ea=[{es:"¿Qué síntomas tiene Diego?",opcoes:["Tos y frío","Fiebre y dolor de cabeza","Solo cansancio","Dolor de muela"],correta:1,pt:"Quais sintomas o Diego tem?"},{es:"¿Qué se torció Diego en la escalera?",opcoes:["El tobillo","El dedo","La rodilla","La muñeca"],correta:0,pt:"O que o Diego torceu na escada?"},{es:"¿Por qué no va caminando al hospital?",opcoes:["Porque está lejos","Porque llueve","Porque no puede caminar bien","Porque no sabe dónde está"],correta:2,pt:"Por que ele não vai caminhando ao hospital?"},{es:"¿Qué decide hacer Ana?",opcoes:["Buscar un taxi","Esperar en casa","Llevarlo en auto","Llamar a una ambulancia"],correta:3,pt:"O que a Ana decide fazer?"},{es:"¿Qué le da Ana a Diego para el dolor?",opcoes:["Una pastilla","Un té","Agua","Nada"],correta:0,pt:"O que a Ana dá ao Diego pra dor?"},{es:"¿Cómo se siente Diego al final?",opcoes:["Mucho peor","Igual que antes","Un poco mejor","Sin fiebre del todo"],correta:2,pt:"Como o Diego se sente no final?"}],oa={id:Ro,nivel:Go,titulo:Jo,subtitulo:wo,introAudioKey:Wo,introPt:Xo,cenario:Zo,dialogo:_o,perguntas:ea},aa="q-i05",sa="intermediario",na="Quiz — Serviços e reclamações",ia="Escute a conversa e responda em espanhol",ra="q-i05-i",ta="Vamos ver se você se vira quando algo dá errado: banco, celular e uma reclamação. Escute a conversa do Diego no balcão e responda.",ua="Diego chega ao balcão de atendimento de uma loja de celular. Comprou um chip há dois dias, mas a internet não funciona. Ana é a atendente.",da=[{audioKey:"q-i05-d1",voz:"Diego",es:"Disculpe, tengo un problema con el chip que compré acá.",pt:"Com licença, tenho um problema com o chip que comprei aqui."},{audioKey:"q-i05-d2",voz:"Ana",es:"Contame, ¿qué pasa? ¿No tenés señal?",pt:"Me conta, o que houve? Você não tem sinal?"},{audioKey:"q-i05-d3",voz:"Diego",es:"Señal sí tengo, pero no funciona internet. No puedo cargar nada.",pt:"Sinal eu tenho, mas a internet não funciona. Não consigo carregar nada."},{audioKey:"q-i05-d4",voz:"Ana",es:"Ah, mirá. ¿Ya recargaste datos o el chip vino sin saldo?",pt:"Ah, olha só. Você já recarregou dados ou o chip veio sem saldo?"},{audioKey:"q-i05-d5",voz:"Diego",es:"Recargué ayer en el cajero, pagué con tarjeta. Pero sigue igual.",pt:"Recarreguei ontem no caixa eletrônico, paguei com cartão. Mas continua igual."},{audioKey:"q-i05-d6",voz:"Ana",es:"Entiendo. Quiero ayudarte, pero esto lo ve el técnico. ¿Querés hacer un reclamo?",pt:"Entendo. Quero te ajudar, mas isso é o técnico que vê. Você quer fazer uma reclamação?"},{audioKey:"q-i05-d7",voz:"Diego",es:"Sí, quiero hacer un reclamo. ¿Con quién puedo hablar?",pt:"Sim, quero fazer uma reclamação. Com quem posso falar?"},{audioKey:"q-i05-d8",voz:"Ana",es:"Hablá con el de la ventanilla tres. Llevá el ticket de la recarga.",pt:"Fale com o da janela três. Leve o comprovante da recarga."},{audioKey:"q-i05-d9",voz:"Diego",es:"Perfecto. ¿Y si no se arregla hoy, me devuelven la plata?",pt:"Perfeito. E se não resolver hoje, vocês me devolvem o dinheiro?"},{audioKey:"q-i05-d10",voz:"Ana",es:"Eso lo decide el técnico. Pero quedate tranquilo, lo solucionamos.",pt:"Isso quem decide é o técnico. Mas fique tranquilo, a gente resolve."}],ca=[{es:"¿Cuál es el problema de Diego?",opcoes:["No tiene señal en el celular","Perdió el chip que compró","No funciona internet en su chip","El cajero no le dio plata"],correta:2,pt:"Qual é o problema do Diego? — A internet do chip dele não funciona."},{es:"¿Dónde y cómo pagó Diego la recarga?",opcoes:["En el cajero, con tarjeta","En la ventanilla, en efectivo","Con el técnico, con dólares","Todavía no recargó nada"],correta:0,pt:"Onde e como Diego pagou a recarga? — No caixa eletrônico, com cartão."},{es:"¿Qué le propone Ana a Diego?",opcoes:["Cambiar el chip ahora mismo","Hacer un reclamo","Devolverle la plata enseguida","Recargar datos otra vez"],correta:1,pt:"O que Ana propõe ao Diego? — Fazer uma reclamação."},{es:"¿Qué tiene que llevar Diego a la ventanilla tres?",opcoes:["El celular y el cajero","La tarjeta del banco","Otro chip nuevo","El ticket de la recarga"],correta:3,pt:"O que Diego precisa levar à janela três? — O comprovante da recarga."},{es:"¿Por qué Ana no resuelve el problema ella misma?",opcoes:["Porque está por cerrar la tienda","Porque ese tema lo ve el técnico","Porque Diego no tiene el ticket","Porque no acepta tarjetas"],correta:1,pt:"Por que Ana não resolve o problema ela mesma? — Porque esse assunto é o técnico que vê."},{es:"¿Quién decide si le devuelven la plata a Diego?",opcoes:["Ana, la que atiende","El banco del cajero","El técnico","Nadie, no se devuelve"],correta:2,pt:"Quem decide se devolvem o dinheiro ao Diego? — O técnico."}],la={id:aa,nivel:sa,titulo:na,subtitulo:ia,introAudioKey:ra,introPt:ta,cenario:ua,dialogo:da,perguntas:ca},pa="q-i06",ma="intermediario",va="Quiz — Socializar",qa="Escute a conversa e responda em espanhol",ga="q-i06-i",ba="Hora de soltar a língua entre amigos: gostos, um convite e uma opinião. Escute a conversa da Ana e do Diego e responda.",Aa="Ana e Diego estão tomando um café e conversam sobre o que gostam de fazer no fim de semana. Ana acaba fazendo um convite.",ha=[{audioKey:"q-i06-d1",voz:"Ana",es:"Che, ¿qué te gusta hacer los fines de semana?",pt:"Ô, do que você gosta de fazer nos fins de semana?"},{audioKey:"q-i06-d2",voz:"Diego",es:"Me encanta el cine. Y me gusta mucho cocinar también.",pt:"Eu adoro cinema. E gosto muito de cozinhar também."},{audioKey:"q-i06-d3",voz:"Ana",es:"¡Qué bueno! A mí no me gusta cocinar, pero me encanta comer.",pt:"Que bom! Eu não gosto de cozinhar, mas adoro comer."},{audioKey:"q-i06-d4",voz:"Diego",es:"Jaja, entonces hacemos buena pareja. ¿Te gusta el cine de terror?",pt:"Haha, então formamos uma boa dupla. Você gosta de filme de terror?"},{audioKey:"q-i06-d5",voz:"Ana",es:"No, el terror no me gusta nada. Prefiero las comedias.",pt:"Não, terror eu não gosto nada. Prefiro as comédias."},{audioKey:"q-i06-d6",voz:"Diego",es:"Dale. Hay una comedia nueva muy buena. ¿Querés ir el sábado?",pt:"Beleza. Tem uma comédia nova muito boa. Você quer ir no sábado?"},{audioKey:"q-i06-d7",voz:"Ana",es:"El sábado no puedo, tengo cumpleaños de mi hermana. ¿El domingo?",pt:"No sábado não posso, é aniversário da minha irmã. No domingo?"},{audioKey:"q-i06-d8",voz:"Diego",es:"El domingo me viene bárbaro. ¿Te parece a la tarde?",pt:"No domingo fica ótimo pra mim. Acha bom à tarde?"},{audioKey:"q-i06-d9",voz:"Ana",es:"Creo que a la tarde está perfecto. Después tomamos algo, ¿sí?",pt:"Acho que à tarde está perfeito. Depois bebemos alguma coisa, sim?"},{audioKey:"q-i06-d10",voz:"Diego",es:"¡Me encantaría! Estoy de acuerdo, cine y después un café.",pt:"Eu adoraria! Concordo, cinema e depois um café."}],za=[{es:"¿Qué le encanta a Diego?",opcoes:["El cine","El terror","Madrugar","El fútbol"],correta:0,pt:"O que o Diego adora? — Cinema."},{es:"¿Qué dice Ana sobre cocinar?",opcoes:["Que le encanta cocinar","Que no le gusta cocinar","Que cocina los domingos","Que prefiere cocinar a comer"],correta:1,pt:"O que Ana diz sobre cozinhar? — Que não gosta de cozinhar."},{es:"¿Qué tipo de película prefiere Ana?",opcoes:["El terror","Las de acción","Las comedias","No le gusta el cine"],correta:2,pt:"Que tipo de filme Ana prefere? — As comédias."},{es:"¿Por qué Ana no puede ir el sábado?",opcoes:["Porque trabaja el sábado","Porque no le gusta el plan","Porque está enferma","Porque tiene el cumpleaños de su hermana"],correta:3,pt:"Por que Ana não pode ir no sábado? — Porque é o aniversário da irmã dela."},{es:"¿Para qué día y momento quedan finalmente?",opcoes:["El sábado a la noche","El domingo a la tarde","El domingo a la mañana","El viernes al mediodía"],correta:1,pt:"Para que dia e momento eles ficam afinal? — Domingo à tarde."},{es:"¿Qué planean hacer después del cine?",opcoes:["Cocinar en casa de Ana","Ir a la cancha","Tomar algo","Volver al trabajo"],correta:2,pt:"O que eles planejam fazer depois do cinema? — Beber alguma coisa."}],ya={id:pa,nivel:ma,titulo:va,subtitulo:qa,introAudioKey:ga,introPt:ba,cenario:Aa,dialogo:ha,perguntas:za},fa="q-i07",Da="intermediario",Ka="Quiz — Cultura rioplatense",Ea="Escute a conversa e responda em espanhol",Pa="q-i07-i",Qa="Esta é a mais cultural de todas: mate, asado, cancha e muita gíria. Escute a conversa entre amigos e responda — preste atenção no che, no bárbaro e no posta.",$a="Diego liga para a Ana num domingo de manhã para combinar o programa do dia: mate, churrasco e talvez o estádio. Conversa entre amigos, bem rioplatense.",Ca=[{audioKey:"q-i07-d1",voz:"Diego",es:"Che, ¿qué onda? ¿Estás despierta?",pt:"Ô, e aí? Você tá acordada?"},{audioKey:"q-i07-d2",voz:"Ana",es:"Sí, recién me levanté. Estoy cebando unos mates. ¿Querés venir?",pt:"Sim, acabei de levantar. Estou preparando uns mates. Quer vir?"},{audioKey:"q-i07-d3",voz:"Diego",es:"¡Dale! Llevo la yerba que la tuya siempre se termina, jaja.",pt:"Beleza! Levo a erva que a sua sempre acaba, haha."},{audioKey:"q-i07-d4",voz:"Ana",es:"Bárbaro. Y a la tarde mi viejo hace un asado, ¿te prendés?",pt:"Ótimo. E à tarde meu pai faz um churrasco, você topa?"},{audioKey:"q-i07-d5",voz:"Diego",es:"¿Un asado? Posta que no me lo pierdo. Tu viejo es un parrillero de diez.",pt:"Um churrasco? Sério que eu não perco. Seu pai é um churrasqueiro nota dez."},{audioKey:"q-i07-d6",voz:"Ana",es:"Es un capo con la parrilla. ¿Y después? Juega River, ¿vamos a la cancha?",pt:"Ele é fera na churrasqueira. E depois? Joga o River, vamos ao estádio?"},{audioKey:"q-i07-d7",voz:"Diego",es:"Uf, a la cancha está difícil, no conseguí entrada. ¿Lo vemos acá?",pt:"Uf, ao estádio tá difícil, não consegui ingresso. A gente vê aqui?"},{audioKey:"q-i07-d8",voz:"Ana",es:"Dale, lo miramos con la hinchada en casa. Igual, primero el mate.",pt:"Beleza, vemos com a torcida em casa. De qualquer jeito, primeiro o mate."},{audioKey:"q-i07-d9",voz:"Diego",es:"Obvio, el mate es sagrado. Salgo para allá. ¿Necesitás algo del super?",pt:"Óbvio, o mate é sagrado. Saio pra aí. Precisa de algo do mercado?"},{audioKey:"q-i07-d10",voz:"Ana",es:"Traé pan para el asado y listo. ¡Nos vemos, che!",pt:"Traz pão pro churrasco e pronto. A gente se vê, ô!"}],ja=[{es:"¿Qué está haciendo Ana cuando Diego la llama?",opcoes:["Está en la cancha","Está cebando unos mates","Está haciendo el asado","Está durmiendo todavía"],correta:1,pt:"O que Ana está fazendo quando Diego liga? — Está preparando uns mates."},{es:"¿Por qué Diego dice que lleva la yerba?",opcoes:["Porque la de Ana siempre se termina","Porque a Ana no le gusta el mate","Porque la suya es más rica","Porque Ana no tiene termo"],correta:0,pt:"Por que Diego diz que leva a erva? — Porque a da Ana sempre acaba."},{es:"¿Quién va a hacer el asado a la tarde?",opcoes:["Diego","Ana","El padre de Ana","La hinchada"],correta:2,pt:"Quem vai fazer o churrasco à tarde? — O pai da Ana."},{es:"¿Por qué no van a la cancha?",opcoes:["Porque no juega River","Porque prefieren el asado","Porque a Diego no le gusta el fútbol","Porque Diego no consiguió entrada"],correta:3,pt:"Por que eles não vão ao estádio? — Porque Diego não conseguiu ingresso."},{es:"¿Qué deciden hacer con el partido?",opcoes:["No mirarlo","Mirarlo en casa con la hinchada","Ir igual a la cancha","Escucharlo por radio en el super"],correta:1,pt:"O que eles decidem fazer com o jogo? — Assistir em casa com a torcida."},{es:"¿Qué le pide Ana que traiga del super?",opcoes:["Más yerba","Carne para el asado","Pan para el asado","Entradas para la cancha"],correta:2,pt:"O que Ana pede que ele traga do mercado? — Pão para o churrasco."}],Sa={id:fa,nivel:Da,titulo:Ka,subtitulo:Ea,introAudioKey:Pa,introPt:Qa,cenario:$a,dialogo:Ca,perguntas:ja},Oa="q-a01",Ua="avancado",Na="Quiz — O subjuntivo",Ma="Escute a conversa e responda em espanhol",Ba="q-a01-i",Ta="Hora de testar o subjuntivo! Escute Ana e Diego e responda em espanhol — desejos, pedidos e dúvidas, tudo junto.",Va="Ana vai viajar amanhã e conversa com Diego, que está meio resfriado, antes de sair.",La=[{audioKey:"q-a01-d1",voz:"Ana",es:"Mañana me voy de viaje, así que vine a despedirme. ¡Espero que te mejores pronto!",pt:"Amanhã viajo, então vim me despedir. Espero que você melhore logo!"},{audioKey:"q-a01-d2",voz:"Diego",es:"Gracias, igualmente. ¡Que tengas un buen viaje! ¿Adónde vas?",pt:"Obrigado, igualmente. Tenha uma boa viagem! Aonde você vai?"},{audioKey:"q-a01-d3",voz:"Ana",es:"A Bariloche. Quiero que vengas conmigo el año que viene, en serio.",pt:"A Bariloche. Quero que você venha comigo no ano que vem, sério."},{audioKey:"q-a01-d4",voz:"Diego",es:"¡Ojalá pueda! Aunque no creo que sea fácil con el laburo. ¿Es muy caro?",pt:"Tomara que eu possa! Embora eu não ache que seja fácil com o trabalho. É muito caro?"},{audioKey:"q-a01-d5",voz:"Ana",es:"No creo que sea tan caro si reservás temprano. Te recomiendo que lo pienses ya.",pt:"Não acho que seja tão caro se você reservar cedo. Recomendo que você pense nisso já."},{audioKey:"q-a01-d6",voz:"Diego",es:"Tenés razón. Necesito que me ayudes a buscar los pasajes cuando vuelvas.",pt:"Você tem razão. Preciso que você me ajude a procurar as passagens quando voltar."},{audioKey:"q-a01-d7",voz:"Ana",es:"¡Dale! Cuando llegue, te escribo y armamos todo. Es mejor que decidamos rápido.",pt:"Combinado! Quando eu chegar, te escrevo e organizamos tudo. É melhor decidirmos rápido."},{audioKey:"q-a01-d8",voz:"Diego",es:"Perfecto. Bueno, andá tranquila. ¡Que descanses y que la pases bien!",pt:"Perfeito. Bom, vá tranquila. Descanse e divirta-se!"},{audioKey:"q-a01-d9",voz:"Ana",es:"Gracias, sos un sol. Cuidate ese resfrío. ¡Nos vemos cuando vuelva!",pt:"Obrigada, você é um amor. Cuide desse resfriado. A gente se vê quando eu voltar!"}],Ha=[{es:"¿Qué le desea Ana a Diego al principio de la charla?",opcoes:["Que tenga un buen viaje","Que se mejore pronto","Que descanse mucho","Que la pase bien"],correta:1,pt:"O que Ana deseja a Diego no começo da conversa?"},{es:"¿Por qué Diego duda en aceptar el viaje?",opcoes:["Porque no le gusta Bariloche","Porque está enfermo","Porque no cree que sea fácil con el trabajo","Porque es demasiado caro"],correta:2,pt:"Por que Diego hesita em aceitar a viagem?"},{es:"Según Ana, ¿cómo se puede gastar menos en el viaje?",opcoes:["Reservando temprano","Viajando en grupo","Yendo en otra temporada","Quedándose menos días"],correta:0,pt:"Segundo Ana, como dá pra gastar menos na viagem?"},{es:"¿Qué le pide Diego a Ana que haga cuando ella vuelva?",opcoes:["Que le preste plata","Que lo llame por teléfono","Que descanse primero","Que lo ayude a buscar los pasajes"],correta:3,pt:"O que Diego pede que Ana faça quando ela voltar?"},{es:"Cuando Ana dice 'cuando llegue, te escribo', se entiende que ella va a escribir…",opcoes:["en este momento","antes de salir de viaje","después de llegar a destino","solo si Diego se lo pide"],correta:2,pt:"Quando Ana diz 'cuando llegue, te escribo', entende-se que ela vai escrever…"},{es:"Por la manera en que terminan, ¿cómo es la relación entre Ana y Diego?",opcoes:["Son apenas compañeros de trabajo","Acaban de conocerse","Son amigos de confianza","Están enojados entre ellos"],correta:2,pt:"Pelo jeito como se despedem, como é a relação entre Ana e Diego?"}],Ya={id:Oa,nivel:Ua,titulo:Na,subtitulo:Ma,introAudioKey:Ba,introPt:Ta,cenario:Va,dialogo:La,perguntas:Ha},ka="q-a02",xa="avancado",Ia="Quiz — Condicional e hipóteses",Fa="Escute a conversa e responda em espanhol",Ra="q-a02-i",Ga="Vamos ver se você pega o condicional! Pedidos educados, hipóteses do 'se eu pudesse' e conselhos — escute e responda em espanhol.",Ja="Diego está estressado com o trabalho e desabafa com Ana, que dá conselhos e fala dos próprios sonhos.",wa=[{audioKey:"q-a02-d1",voz:"Diego",es:"Ana, ¿podrías escucharme un momento? Estoy reventado con el laburo.",pt:"Ana, você poderia me escutar um momento? Estou acabado com o trabalho."},{audioKey:"q-a02-d2",voz:"Ana",es:"Claro, contame. Se te ve agotado. ¿Qué harías si pudieras cambiar algo?",pt:"Claro, me conta. Você está com cara de esgotado. O que você faria se pudesse mudar algo?"},{audioKey:"q-a02-d3",voz:"Diego",es:"Si tuviera valor, renunciaría y me tomaría un año sabático.",pt:"Se eu tivesse coragem, pediria demissão e tiraria um ano sabático."},{audioKey:"q-a02-d4",voz:"Ana",es:"Yo que vos, no renunciaría sin un plan. Deberías hablar con tu jefe primero.",pt:"Eu, no seu lugar, não pediria demissão sem um plano. Você deveria falar com seu chefe primeiro."},{audioKey:"q-a02-d5",voz:"Diego",es:"¿Y vos qué harías en mi lugar, hablando en serio?",pt:"E você, o que faria no meu lugar, falando sério?"},{audioKey:"q-a02-d6",voz:"Ana",es:"Pediría menos horas. Si trabajara menos, tendría tiempo para mí y descansaría.",pt:"Eu pediria menos horas. Se trabalhasse menos, teria tempo pra mim e descansaria."},{audioKey:"q-a02-d7",voz:"Diego",es:"Tenés razón. Tendría que animarme a pedirlo. ¿Me ayudarías a prepararlo?",pt:"Você tem razão. Eu teria que me animar a pedir. Você me ajudaria a preparar isso?"},{audioKey:"q-a02-d8",voz:"Ana",es:"Obvio. Y si yo tuviera plata, me iría a estudiar afuera un tiempo, así que te entiendo.",pt:"Claro. E se eu tivesse dinheiro, iria estudar fora um tempo, então eu te entendo."},{audioKey:"q-a02-d9",voz:"Diego",es:"¡Sería genial! Bueno, mañana mismo hablo con él. Gracias por el consejo.",pt:"Seria ótimo! Bom, amanhã mesmo falo com ele. Obrigado pelo conselho."}],Wa=[{es:"¿Cómo le pide Diego a Ana que lo escuche?",opcoes:["De forma educada, con '¿podrías?'","Con una orden directa","Gritándole","Por mensaje de texto"],correta:0,pt:"Como Diego pede que Ana o escute?"},{es:"¿Qué haría Diego si tuviera valor?",opcoes:["Hablaría con su jefe","Pediría menos horas","Renunciaría y se tomaría un año sabático","Estudiaría en el exterior"],correta:2,pt:"O que Diego faria se tivesse coragem?"},{es:"¿Qué le aconseja Ana usando 'yo que vos'?",opcoes:["Que renuncie cuanto antes","Que no renuncie sin un plan","Que se tome vacaciones","Que cambie de ciudad"],correta:1,pt:"O que Ana aconselha usando 'yo que vos'?"},{es:"Según Ana, ¿qué pasaría si ella trabajara menos?",opcoes:["Ganaría más plata","Se aburriría en casa","Buscaría otro empleo","Tendría tiempo para sí misma y descansaría"],correta:3,pt:"Segundo Ana, o que aconteceria se ela trabalhasse menos?"},{es:"¿Qué se entiende sobre el sueño de Ana de estudiar afuera?",opcoes:["Que ya está estudiando afuera","Que es algo que no puede hacer ahora por falta de plata","Que se va el mes que viene","Que ya no le interesa"],correta:1,pt:"O que se entende sobre o sonho de Ana de estudar fora?"},{es:"¿Qué decide hacer Diego al final de la charla?",opcoes:["Renunciar de inmediato","No hacer nada por ahora","Hablar con su jefe al día siguiente","Pedirle plata a Ana"],correta:2,pt:"O que Diego decide fazer no fim da conversa?"}],Xa={id:ka,nivel:xa,titulo:Ia,subtitulo:Fa,introAudioKey:Ra,introPt:Ga,cenario:Ja,dialogo:wa,perguntas:Wa},Za="q-a03",_a="avancado",es="Quiz — Conectores e argumentação",os="Escute a conversa e responda em espanhol",as="q-a03-i",ss="Último teste do avançado: conectores e argumentação. Escute como Ana e Diego defendem suas ideias e responda em espanhol.",ns="Ana e Diego discutem se vale a pena comprar um apartamento perto do centro ou alugar mais longe.",is=[{audioKey:"q-a03-d1",voz:"Ana",es:"Para mí, deberíamos comprar el departamento del centro, aunque sea más chico.",pt:"Pra mim, deveríamos comprar o apartamento do centro, mesmo que seja menor."},{audioKey:"q-a03-d2",voz:"Diego",es:"Entiendo tu punto, pero es carísimo. Además, está bastante viejo.",pt:"Entendo seu ponto, mas é caríssimo. Além disso, está bem velho."},{audioKey:"q-a03-d3",voz:"Ana",es:"Es caro, sin embargo, queda al lado del trabajo, así que ahorraríamos en transporte.",pt:"É caro, no entanto, fica do lado do trabalho, então economizaríamos em transporte."},{audioKey:"q-a03-d4",voz:"Diego",es:"En eso estoy de acuerdo. Pero, por otro lado, alquilar afuera nos saldría mucho menos.",pt:"Nisso eu concordo. Mas, por outro lado, alugar mais longe nos sairia bem mais barato."},{audioKey:"q-a03-d5",voz:"Ana",es:"Sí, aunque alquilando nunca sería nuestro. Por eso prefiero comprar.",pt:"Sim, embora alugando nunca seria nosso. Por isso prefiro comprar."},{audioKey:"q-a03-d6",voz:"Diego",es:"No estoy de acuerdo del todo. Depende de cuánto tiempo pensemos quedarnos.",pt:"Não concordo totalmente. Depende de quanto tempo pensamos ficar."},{audioKey:"q-a03-d7",voz:"Ana",es:"Tenés razón en eso. Igual, en mi opinión, comprar es invertir, no gastar.",pt:"Você tem razão nisso. Mesmo assim, na minha opinião, comprar é investir, não gastar."},{audioKey:"q-a03-d8",voz:"Diego",es:"Bueno, hagamos una cosa: lo visitamos otra vez y después decidimos con calma.",pt:"Bom, vamos fazer assim: visitamos de novo e depois decidimos com calma."},{audioKey:"q-a03-d9",voz:"Ana",es:"Dale. En resumen, vos querés ahorrar y yo quiero invertir; busquemos el equilibrio.",pt:"Combinado. Em resumo, você quer economizar e eu quero investir; vamos buscar o equilíbrio."}],rs=[{es:"¿Cuál es la postura de Ana al abrir la conversación?",opcoes:["Que conviene alquilar afuera","Que no hay que mudarse","Que deberían comprar el del centro","Que el centro es demasiado caro"],correta:2,pt:"Qual é a posição de Ana ao abrir a conversa?"},{es:"¿Qué argumentos usa Diego en contra del departamento del centro?",opcoes:["Que es caro y está viejo","Que está lejos del trabajo","Que es muy ruidoso","Que no tiene luz"],correta:0,pt:"Que argumentos Diego usa contra o apartamento do centro?"},{es:"Con 'sin embargo, queda al lado del trabajo', Ana quiere…",opcoes:["darle la razón a Diego","contrastar con el precio alto y defender el centro","cambiar de tema","cerrar la discusión"],correta:1,pt:"Com 'sin embargo, queda al lado del trabajo', Ana quer…"},{es:"¿Por qué Ana prefiere comprar y no alquilar?",opcoes:["Porque alquilar es más caro","Porque el centro es más lindo","Porque alquilando la casa nunca sería de ellos","Porque no le gusta el barrio de afuera"],correta:2,pt:"Por que Ana prefere comprar e não alugar?"},{es:"Cuando Diego dice 'no estoy de acuerdo del todo', significa que…",opcoes:["está completamente en contra","concuerda en parte, pero no totalmente","ya decidió comprar","no quiere opinar"],correta:1,pt:"Quando Diego diz 'no estoy de acuerdo del todo', significa que…"},{es:"¿Cómo terminan la discusión Ana y Diego?",opcoes:["Enojados, sin acuerdo","Decidiendo comprar ya mismo","Decidiendo alquilar afuera","Posponiendo la decisión para visitar de nuevo"],correta:3,pt:"Como Ana e Diego terminam a discussão?"}],ts={id:Za,nivel:_a,titulo:es,subtitulo:os,introAudioKey:as,introPt:ss,cenario:ns,dialogo:is,perguntas:rs},us="q-a04",ds="avancado",cs="Quiz — Modismos e registros",ls="Escute a conversa e responda em espanhol",ps="q-a04-i",ms="Hora de testar o ouvido com os modismos rioplatenses. Escute a conversa entre Ana e Diego e responda em espanhol — repare no que cada expressão quer dizer de verdade.",vs="Ana e Diego conversam sobre um plano de fim de semana que mudou de última hora; depois aparece um vizinho mais velho e o tom muda.",qs=[{audioKey:"q-a04-d1",voz:"Diego",es:"Che, se canceló el recital del sábado. ¡Qué bajón!",pt:"Ei, cancelaram o show de sábado. Que decepção!"},{audioKey:"q-a04-d2",voz:"Ana",es:"Uy, qué lástima. Pero está todo bien, armamos otra cosa.",pt:"Ai, que pena. Mas tá tudo certo, a gente inventa outra coisa."},{audioKey:"q-a04-d3",voz:"Diego",es:"¿Y si vamos al asado de Martín? Dicen que está bárbaro el lugar nuevo.",pt:"E se a gente for no churrasco do Martín? Dizem que o lugar novo tá ótimo."},{audioKey:"q-a04-d4",voz:"Ana",es:"Me da igual, decidí vos. Yo me prendo a lo que sea.",pt:"Tanto faz, decide você. Eu topo qualquer coisa."},{audioKey:"q-a04-d5",voz:"Diego",es:"Dale. ¿Llevamos algo? ¿Vino, postre…?",pt:"Beleza. Levamos algo? Vinho, sobremesa…?"},{audioKey:"q-a04-d6",voz:"Ana",es:"Ni idea de qué falta. Mandale un mensaje y preguntale.",pt:"Não faço ideia do que falta. Manda uma mensagem e pergunta pra ele."},{audioKey:"q-a04-d7",voz:"Diego",es:"Listo. Ah, ahí viene el señor del tercero. Saludá bien.",pt:"Pronto. Ah, lá vem o senhor do terceiro andar. Cumprimenta direito."},{audioKey:"q-a04-d8",voz:"Ana",es:"Buenas tardes, ¿cómo está usted? ¿Necesita una mano con las bolsas?",pt:"Boa tarde, como o senhor está? Precisa de uma mãozinha com as sacolas?"},{audioKey:"q-a04-d9",voz:"Diego",es:"Tranquilo, nosotros lo ayudamos. Que tenga un buen día.",pt:"Fique tranquilo, nós o ajudamos. Tenha um bom dia."}],gs=[{es:"¿Qué le pasó a Diego al principio?",opcoes:["Se ganó una entrada","Se canceló el recital y está decepcionado","No le gusta el recital","Llegó tarde al recital"],correta:1,pt:"Pergunta sobre 'qué bajón': Diego está decepcionado porque o show foi cancelado."},{es:"Cuando Ana dice «me da igual, decidí vos», quiere decir que…",opcoes:["No quiere ir a ningún lado","Le da lo mismo, que elija Diego","Está enojada con Diego","Prefiere quedarse en casa"],correta:1,pt:"'Me da igual' = tanto faz; ela deixa Diego decidir."},{es:"¿Qué significa que el lugar nuevo «está bárbaro»?",opcoes:["Que es muy caro","Que es peligroso","Que es muy bueno","Que está cerrado"],correta:2,pt:"Falso amigo: 'bárbaro' no rioplatense é elogio = ótimo."},{es:"Ana responde «ni idea de qué falta». Eso significa que…",opcoes:["No sabe qué hace falta llevar","Ya tiene todo lo necesario","No quiere llevar nada","Va a comprar todo ella"],correta:0,pt:"'Ni idea' = não faço ideia; ela não sabe o que falta levar."},{es:"¿Por qué cambia el tono cuando aparece el señor del tercero?",opcoes:["Porque están enojados con él","Porque tienen apuro","Porque le hablan con respeto, usando usted","Porque no lo conocen de nada"],correta:2,pt:"Inferência de registro: com o vizinho mais velho passam ao formal 'usted'."},{es:"¿Cuál de estas frases es del registro FORMAL (usted)?",opcoes:["¿Cómo estás vos?","Mandale un mensaje","Decidí vos","Que tenga un buen día"],correta:3,pt:"Reconhecer o formal: 'que tenga' usa o verbo na 3ª pessoa (usted)."}],bs={id:us,nivel:ds,titulo:cs,subtitulo:ls,introAudioKey:ps,introPt:ms,cenario:vs,dialogo:qs,perguntas:gs},As="q-a05",hs="avancado",zs="Quiz — Trâmites e negócios",ys="Escute a conversa e responda em espanhol",fs="q-a05-i",Ds="Vamos ver se você se vira numa repartição e numa conversa de trabalho. Escute o atendimento formal entre Ana e Diego e responda em espanhol — atenção aos falsos amigos.",Ks="Diego chega a um escritório de atendimento para resolver uma papelada e, na sequência, fecha detalhes de um orçamento. Ana é a atendente; todo o trato é no formal usted.",Es=[{audioKey:"q-a05-d1",voz:"Diego",es:"Buenos días. Vengo a hacer un trámite, ¿tengo que sacar turno?",pt:"Bom dia. Vim resolver uma papelada, preciso marcar hora?"},{audioKey:"q-a05-d2",voz:"Ana",es:"Buenos días. Sin turno no puedo atenderlo, pero tengo un lugar a las once.",pt:"Bom dia. Sem senha não posso te atender, mas tenho um horário às onze."},{audioKey:"q-a05-d3",voz:"Diego",es:"Perfecto. ¿Qué documentación necesito traer?",pt:"Perfeito. Que documentos preciso trazer?"},{audioKey:"q-a05-d4",voz:"Ana",es:"El documento de identidad y el comprobante de domicilio. Después firma acá.",pt:"O documento de identidade e o comprovante de residência. Depois assina aqui."},{audioKey:"q-a05-d5",voz:"Diego",es:"De acuerdo. Y por el otro tema, ¿me puede enviar el presupuesto?",pt:"Combinado. E sobre o outro assunto, o senhor pode me enviar o orçamento?"},{audioKey:"q-a05-d6",voz:"Ana",es:"Claro, se lo envío hoy mismo. ¿Cuál es el plazo que maneja usted?",pt:"Claro, envio ao senhor hoje mesmo. Qual é o prazo que o senhor trabalha?"},{audioKey:"q-a05-d7",voz:"Diego",es:"Lo necesito para fin de mes. Si pago en efectivo, ¿me hace un descuento?",pt:"Preciso pra fim do mês. Se eu pagar à vista, o senhor me faz um desconto?"},{audioKey:"q-a05-d8",voz:"Ana",es:"Algo podemos ver. Eso sí, hubo un error en la última factura.",pt:"Algo a gente pode ver. Mas atenção: houve um erro na última fatura."},{audioKey:"q-a05-d9",voz:"Diego",es:"Justamente, quisiera hacer un reclamo por eso. Quedo a la espera de su respuesta.",pt:"Justamente, eu gostaria de fazer uma reclamação por isso. Fico no aguardo da sua resposta."}],Ps=[{es:"¿Por qué Ana no puede atender a Diego enseguida?",opcoes:["Porque vino sin turno","Porque le faltan documentos","Porque la oficina está cerrada","Porque no es su día de atención"],correta:0,pt:"'Sin turno no puedo atenderlo': sem hora marcada não dá pra atender na hora."},{es:"¿Qué documentación le pide Ana?",opcoes:["Solo el documento de identidad","El pasaporte y una foto","El documento de identidad y el comprobante de domicilio","Nada, no hace falta"],correta:2,pt:"Compreensão direta: documento de identidade + comprovante de residência."},{es:"Cuando Diego pide «el presupuesto», ¿qué está pidiendo?",opcoes:["Un pressuposto/teoria","El orçamento (la estimación de costos)","Un recibo de pago","Una autorización"],correta:1,pt:"Falso amigo: 'presupuesto' = orçamento, não 'pressuposto'."},{es:"¿Qué quiere decir «el plazo» en la conversación?",opcoes:["El lugar de entrega","La forma de pago","El prazo (el tiempo de entrega)","El precio final"],correta:2,pt:"Falso amigo: 'plazo' = prazo, tempo de entrega."},{es:"¿Qué condición pone Diego para pedir un descuento?",opcoes:["Pagar en cuotas","Pagar en efectivo","Comprar más cantidad","Firmar un contrato largo"],correta:1,pt:"Inferência: o desconto está condicionado a pagar 'en efectivo' (à vista)."},{es:"Al final, ¿qué decide hacer Diego por el error en la factura?",opcoes:["Hacer un reclamo formal","No pagar nada","Cambiar de empresa","Ignorar el problema"],correta:0,pt:"'Quisiera hacer un reclamo': ele decide reclamar formalmente."}],Qs={id:As,nivel:hs,titulo:zs,subtitulo:ys,introAudioKey:fs,introPt:Ds,cenario:Ks,dialogo:Es,perguntas:Ps},$s="q-a06",Cs="avancado",js="Quiz — Entender o nativo",Ss="Escute a conversa e responda em espanhol",Os="q-a06-i",Us="O teste final do ouvido! Ana e Diego falam em ritmo natural, cheios de muletillas. Não precisa pegar cada palavra — pegue o miolo e responda em espanhol.",Ns="Ana conta a Diego, em ritmo rápido e com muitas muletillas, sobre um restaurante novo. Diego, em parte, pede pra repetir.",Ms=[{audioKey:"q-a06-d1",voz:"Ana",es:"Che, fui al lugar nuevo de la esquina y, o sea, estaba buenísimo, ¿viste?",pt:"Ei, fui no lugar novo da esquina e, ou seja, estava ótimo, sabe?"},{audioKey:"q-a06-d2",voz:"Diego",es:"Perdón, ¿podés hablar un poco más despacio? No te entendí bien.",pt:"Desculpe, pode falar um pouco mais devagar? Não te entendi bem."},{audioKey:"q-a06-d3",voz:"Ana",es:"Sí, dale, disculpá. Que fui al restaurante nuevo, digamos, el de la esquina.",pt:"Sim, claro, desculpa. Que fui no restaurante novo, digamos, o da esquina."},{audioKey:"q-a06-d4",voz:"Diego",es:"Ah, ese. ¿Y qué tal? ¿Caro?",pt:"Ah, aquele. E aí, como foi? Caro?"},{audioKey:"q-a06-d5",voz:"Ana",es:"Este… medio carito, sí, pero la comida, nada, espectacular.",pt:"É… meio carinho, sim, mas a comida, enfim, espetacular."},{audioKey:"q-a06-d6",voz:"Diego",es:"¿Cómo se dice eso que pediste? No me acuerdo del nombre.",pt:"Como se diz aquilo que você pediu? Não lembro o nome."},{audioKey:"q-a06-d7",voz:"Ana",es:"A ver… era un plato de pescado, no me sale el nombre ahora.",pt:"Deixa ver… era um prato de peixe, não me vem o nome agora."},{audioKey:"q-a06-d8",voz:"Diego",es:"Entonces, ¿decís que vale la pena ir? Para confirmar.",pt:"Então, você está dizendo que vale a pena ir? Só pra confirmar."},{audioKey:"q-a06-d9",voz:"Ana",es:"Tal cual. O sea, sí, volvería sin pensarlo, ¿viste?",pt:"Exatamente. Ou seja, sim, eu voltaria sem pensar, sabe?"}],Bs=[{es:"¿Qué le pide Diego a Ana al principio?",opcoes:["Que hable más fuerte","Que hable más despacio","Que repita el precio","Que cambie de tema"],correta:1,pt:"'Más despacio': Diego pede pra ela falar mais devagar."},{es:"La palabra «o sea» que usa Ana, ¿para qué sirve?",opcoes:["Para reformular lo que dice (es una muletilla)","Para pedir disculpas","Para preguntar la hora","Para despedirse"],correta:0,pt:"Muletilla: 'o sea' reformula = nosso 'ou seja'."},{es:"Cuando Ana dice «este…» antes de responder, está…",opcoes:["Enojada","Ganando tiempo para pensar","Cambiando de idioma","Terminando la charla"],correta:1,pt:"'Este…' é a pausa pra pensar, equivale a 'é…/então…'."},{es:"¿Qué opina Ana del restaurante?",opcoes:["Que es barato y malo","Que no volvería","Que es medio caro pero la comida es excelente","Que estaba cerrado"],correta:2,pt:"Compreensão do miolo: meio caro, mas a comida espetacular."},{es:"Cuando Diego dice «entonces, ¿decís que vale la pena ir?», ¿qué está haciendo?",opcoes:["Cambiando de plan","Quejándose de Ana","Pidiendo la cuenta","Repitiendo lo que entendió para confirmar"],correta:3,pt:"Inferência: ele repete o que entendeu para confirmar o sentido."},{es:"Ana cierra con «tal cual». Eso quiere decir que…",opcoes:["Está totalmente de acuerdo","No sabe la respuesta","Quiere irse","No le gustó"],correta:0,pt:"'Tal cual' = exatamente; ela concorda totalmente."}],Ts={id:$s,nivel:Cs,titulo:js,subtitulo:Ss,introAudioKey:Os,introPt:Us,cenario:Ns,dialogo:Ms,perguntas:Bs},Vs=[p,f,O],o=[k,Z,ue,Ae,$e,Ve,Je,no,qo,Eo,Mo,Fo,oa,la,ya,Sa,Ya,Xa,ts,bs,Qs,Ts].map(e=>e),Ls=[...o,...Vs];function Hs(e){return Ls.find(a=>a.id===e)}const Ys=Object.fromEntries(o.map(e=>[e.id.replace(/^q-/,""),e.id])),ks={basico:"q-basico",intermediario:"q-intermediario",avancado:"q-avancado"};export{Ls as a,ks as e,Hs as g,Ys as q};
